import './ProgressBar.scss';

import type { BarChartProps, ProgressBarValue } from ':components/ProgressBar/ProgressBar.types';
import { classNames } from ':helpers/classnames';
import * as colors from '@beeline/design-tokens/js/tokens/globals/colors';
import React, { useRef } from 'react';

const ChartPiece = ({ piece, onMouseMove, onMouseLeave }) => {
	const { value, color } = piece;

	const [isHovered, setHovered] = React.useState(false);
	const colorToken = isHovered ? colors[`colorChart${color}Active`] : colors[`colorChart${color}`];
	const pieceRef = useRef<HTMLDivElement | null>(null);
	return (
		<div
			ref={pieceRef}
			onMouseMove={event => {
				setHovered(true);
				onMouseMove?.(event, piece, pieceRef);
			}}
			onMouseLeave={event => {
				setHovered(false);
				onMouseLeave?.(event, piece, pieceRef);
			}}
			className={classNames('progressbar__barchart__chartpiece')}
			style={{ backgroundColor: colorToken, width: `${value}%` }}
			data-testid={`bar-piece-${piece.label || 'unknown'}`}
		></div>
	);
};

export const BarChart: React.FC<Omit<BarChartProps, 'type'>> = ({
	values,
	height,
	width,
	maxValue = 100,
	onMouseLeave,
	onMouseMove,
	className,
}) => {
	const calculatedValues =
		maxValue === 100
			? values
			: values.map(item => ({
					...item,
					value: (item.value / maxValue) * 100,
				}));

	return (
		<div
			className={classNames('progressbar__barchart', className)}
			style={{ borderRadius: height / 2, width: width, height: height }}
			data-testid="progressbar"
			role="progressbar"
			aria-valuemax={maxValue}
			aria-valuemin={0}
			aria-valuenow={calculatedValues.reduce((sum, i) => (sum += i.value), 0)}
		>
			{calculatedValues.map((item: ProgressBarValue, index) => (
				<ChartPiece key={index} piece={item} onMouseMove={onMouseMove} onMouseLeave={onMouseLeave} />
			))}
		</div>
	);
};
